mapper.sql:
WHERE 1 = 1
AND system_activities.created >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND system_activities.created < (TO_DATE(#{endDate}, 'YYYY-MM-DD') + INTERVAL '1 day')
AND system_activities.module_id = #{moduleId}
AND system_activities.created_by = #{userId}
AND system_activities.status = #{status}
AND LOWER(COALESCE(system_activities.action, '')) = LOWER(#{action})
AND LOWER(COALESCE(system_activities.module, '')) = LOWER(#{module})
AND LOWER(COALESCE(system_activities.endpoint, '')) = LOWER(#{endpoint})
AND ( COALESCE(system_activities.endpoint, '') ILIKE '%' || #{searchText} || '%' OR COALESCE(system_activities.module, '') ILIKE '%' || #{searchText} || '%' OR COALESCE(system_activities.action, '') ILIKE '%' || #{searchText} || '%' OR COALESCE(system_activities.description, '') ILIKE '%' || #{searchText} || '%' OR COALESCE(system_activities.ip, '') ILIKE '%' || #{searchText} || '%' OR COALESCE(system_activities.host_name, '') ILIKE '%' || #{searchText} || '%' OR COALESCE(u.username, '') ILIKE '%' || #{searchText} || '%' OR COALESCE(u.first_name, '') ILIKE '%' || #{searchText} || '%' OR COALESCE(u.last_name, '') ILIKE '%' || #{searchText} || '%' )

mapper.select:
SELECT



ORDER BY


        ${orderBy}


        system_activities.id DESC


LIMIT #{rowsPerPage} OFFSET #{page}

mapper.insert:
INSERT INTO system_activities (
    endpoint, module, module_id, action, description, bug, line_code, browser, operating_system, ip, host_name, duration, created_by, created, status
) VALUES (
             #{endpoint}, #{module}, #{moduleId}, #{act}, #{description}, #{bug}, #{line}, #{browser}, #{operatingSystem}, #{ip}, #{hostName}, #{duration}, #{createdBy}, NOW(), #{status}
         )
